function AlertButton() {
  function handleClick() {
    alert('Clicked!');
  }

  return (
    <>
      {/* ✅ Correct: pass a reference — React calls it later */}
      <button onClick={handleClick}>Click me</button>

      {/* ❌ Wrong: calls handleClick() RIGHT NOW during render */}
      <button onClick={handleClick()}>Click me</button>
    </>
  );
}

// 1. Named function defined in the component body (preferred for non-trivial logic)
function Counter() {
  const [count, setCount] = useState(0);

  function handleClick() {
    setCount(count + 1);
  }

  return <button onClick={handleClick}>Count: {count}</button>;
}

// 2. Arrow function defined inline (fine for short one-liners)
function Counter() {
  const [count, setCount] = useState(0);

  return (
    <button onClick={() => setCount(count + 1)}>Count: {count}</button>
  );
}

// 3. Arrow function wrapping a named handler (use when you need to pass arguments)
function ItemList({ items, onDelete }) {
  return (
    <ul>
      {items.map(item => (
        <li key={item.id}>
          {item.name}
          <button onClick={() => onDelete(item.id)}>Delete</button>
        </li>
      ))}
    </ul>
  );
}

function Form() {
  function handleSubmit(event) {
    event.preventDefault();      // prevent the page from reloading
    console.log(event.target);   // the <form> DOM element
  }

  function handleChange(event) {
    console.log(event.target.value); // current input value
  }

  return (
    <form onSubmit={handleSubmit}>
      <input onChange={handleChange} />
      <button type="submit">Submit</button>
    </form>
  );
}

// Component with multiple handlers — all prefixed with 'handle'
function LoginForm() {
  function handleEmailChange(e)  { /* ... */ }
  function handlePasswordChange(e) { /* ... */ }
  function handleSubmit(e)       { /* ... */ }
  function handleReset()         { /* ... */ }

  return (
    <form onSubmit={handleSubmit}>
      <input type="email"    onChange={handleEmailChange} />
      <input type="password" onChange={handlePasswordChange} />
      <button type="submit">Login</button>
      <button type="button" onClick={handleReset}>Reset</button>
    </form>
  );
}

// Child exposes 'onSelect' as a prop
function ColorPicker({ onSelect }) {
  const colors = ['red', 'green', 'blue'];
  return (
    <div>
      {colors.map(c => (
        <button key={c} onClick={() => onSelect(c)}>{c}</button>
      ))}
    </div>
  );
}

// Parent wires it up with a handler
function App() {
  function handleColorSelect(color) {
    console.log('selected:', color);
  }

  return <ColorPicker onSelect={handleColorSelect} />;
}

function Toolbar() {
  return (
    <div onClick={() => console.log('div clicked')}>
      <button onClick={() => console.log('button clicked')}>
        Click me
      </button>
    </div>
  );
  // Clicking the button logs:
  // "button clicked"
  // "div clicked"   ← bubbles up to the parent div
}

// To stop bubbling, call stopPropagation on the event
function Toolbar() {
  return (
    <div onClick={() => console.log('div clicked')}>
      <button
        onClick={e => {
          e.stopPropagation(); // prevents div's onClick from firing
          console.log('button clicked');
        }}
      >
        Click me
      </button>
    </div>
  );
}

function SearchForm({ onSearch }) {
  const [query, setQuery] = useState('');

  function handleSubmit(e) {
    e.preventDefault(); // ← stop the browser from navigating away
    onSearch(query);
  }

  return (
    <form onSubmit={handleSubmit}>
      <input
        value={query}
        onChange={e => setQuery(e.target.value)}
        placeholder="Search..."
      />
      <button type="submit">Go</button>
    </form>
  );
}

function TagInput({ onAddTag }) {
  const [value, setValue] = useState('');

  function handleKeyDown(e) {
    if (e.key === 'Enter') {
      e.preventDefault();
      if (value.trim()) {
        onAddTag(value.trim());
        setValue('');
      }
    }
    if (e.key === 'Escape') {
      setValue('');
    }
  }

  return (
    <input
      value={value}
      onChange={e => setValue(e.target.value)}
      onKeyDown={handleKeyDown}
      placeholder="Type a tag and press Enter"
    />
  );
}

// ❌ This does NOT work — onClick on a custom component does nothing by itself
<MyButton onClick={handleClick}>Click</MyButton>

// ✅ MyButton must pass the onClick prop to a real HTML element
function MyButton({ onClick, children }) {
  return (
    <button className="my-btn" onClick={onClick}>
      {children}
    </button>
  );
}

// Now this works — MyButton forwards the prop to <button>
<MyButton onClick={handleClick}>Click</MyButton>

function FormDemo() {
  const [text, setText]       = useState('');
  const [checked, setChecked] = useState(false);
  const [option, setOption]   = useState('a');

  return (
    <form>
      {/* Text input: read event.target.value */}
      <input
        type="text"
        value={text}
        onChange={e => setText(e.target.value)}
      />

      {/* Checkbox: read event.target.checked */}
      <input
        type="checkbox"
        checked={checked}
        onChange={e => setChecked(e.target.checked)}
      />

      {/* Select: read event.target.value */}
      <select value={option} onChange={e => setOption(e.target.value)}>
        <option value="a">Option A</option>
        <option value="b">Option B</option>
      </select>
    </form>
  );
}

const MAX = 280;

function CommentBox({ onPost }) {
  const [text, setText]     = useState('');
  const [focused, setFocused] = useState(false);
  const remaining = MAX - text.length;

  function handleChange(e) {
    if (e.target.value.length <= MAX) {
      setText(e.target.value);
    }
  }

  function handleKeyDown(e) {
    // Ctrl+Enter or Cmd+Enter submits
    if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {
      handlePost();
    }
  }

  function handlePost() {
    if (!text.trim()) return;
    onPost(text.trim());
    setText('');
  }

  function handleClear(e) {
    e.preventDefault(); // prevent form submission if inside a form
    setText('');
  }

  return (
    <div className={focused ? 'box focused' : 'box'}>
      <textarea
        value={text}
        onChange={handleChange}
        onKeyDown={handleKeyDown}
        onFocus={() => setFocused(true)}
        onBlur={() => setFocused(false)}
        placeholder="Write a comment..."
      />
      <div className="toolbar">
        <span style={{ color: remaining < 20 ? 'red' : 'gray' }}>
          {remaining} remaining
        </span>
        <button onClick={handleClear} disabled={!text}>Clear</button>
        <button onClick={handlePost}  disabled={!text.trim()}>Post</button>
      </div>
    </div>
  );
}

// ❌ BAD: subscribes on every render, never removed
function Button() {
  document.addEventListener('click', handleClick); // runs on every render!
  return <button>Click</button>;
}

// ✅ GOOD: use the React event prop
function Button() {
  return <button onClick={handleClick}>Click</button>;
}

// ✅ ALSO OK (for global events like window resize or keydown):
// use useEffect with a cleanup function — covered in the Effects section

// ❌ BAD: checkbox returns "on" or "" for e.target.value — not what you want
<input type="checkbox" onChange={e => setChecked(e.target.value)} />

// ✅ GOOD: use e.target.checked for checkboxes
<input type="checkbox" onChange={e => setChecked(e.target.checked)} />

// Fine for simple one-liners
<button onClick={() => setCount(c => c + 1)}>+</button>

// Prefer a named function when logic is non-trivial
function handleIncrement() {
  setCount(c => c + 1);
  analytics.track('button_click');
}
<button onClick={handleIncrement}>+</button>

import { render, screen, fireEvent } from '@testing-library/react';
import Counter from './Counter';

test('increments count on button click', () => {
  render(<Counter />);
  const button = screen.getByRole('button', { name: /count/i });

  expect(button).toHaveTextContent('Count: 0');
  fireEvent.click(button);
  expect(button).toHaveTextContent('Count: 1');
  fireEvent.click(button);
  expect(button).toHaveTextContent('Count: 2');
});

test('calls onPost callback with trimmed text', () => {
  const onPost = jest.fn();
  render(<CommentBox onPost={onPost} />);

  fireEvent.change(screen.getByRole('textbox'), {
    target: { value: '  Hello  ' },
  });
  fireEvent.click(screen.getByRole('button', { name: 'Post' }));

  expect(onPost).toHaveBeenCalledWith('Hello');
});
